// Login to backend and return access token
const input = $input.first().json;
const creds = JSON.parse(input.credentials || '{}');
const backendUrl = input.backend_url;
const tenantSlug = input.tenant_slug;

const resp = await this.helpers.httpRequest({
  method: 'POST',
  url: backendUrl + '/api/auth/login',
  headers: {
    'Content-Type': 'application/json',
    'x-tenant-slug': tenantSlug,
  },
  body: { email: creds.email, password: creds.password },
  json: true,
  timeout: 15000,
});

if (!resp || !resp.access_token) {
  throw new Error('Login failed: no access_token returned');
}

// Pass through all input + binary data
return [{ json: { ...input, access_token: resp.access_token }, binary: $input.first().binary }];

// Upload to generic endpoint via manual multipart (no external modules)
const input = $input.first().json;
const token = input.access_token;
const backendUrl = input.backend_url;
const tenantSlug = input.tenant_slug;

const binaryData = $input.first().binary || {};
const boqBinary = binaryData.boq_file;
const specBinary = binaryData.spec_file;

if (!boqBinary || !specBinary) {
  throw new Error('Missing binary file inputs (boq_file, spec_file)');
}

const boundary = '----n8nUpload' + Date.now();
const CRLF = '\r\n';

function fieldPart(name, value) {
  return Buffer.from('--' + boundary + CRLF + 'Content-Disposition: form-data; name="' + name + '"' + CRLF + CRLF + value + CRLF);
}
function filePart(name, filename, contentType, data) {
  const header = '--' + boundary + CRLF + 'Content-Disposition: form-data; name="' + name + '"; filename="' + filename + '"' + CRLF + 'Content-Type: ' + contentType + CRLF + CRLF;
  return [Buffer.from(header), data, Buffer.from(CRLF)];
}

const parts = [];

// File parts
const boqData = Buffer.from(boqBinary.data, 'base64');
const boqName = boqBinary.fileName || 'boq.xlsx';
const boqMime = boqBinary.mimeType || 'application/octet-stream';
parts.push(...filePart('boq_file', boqName, boqMime, boqData));

const specData = Buffer.from(specBinary.data, 'base64');
const specName = specBinary.fileName || 'specification.pdf';
const specMime = specBinary.mimeType || 'application/pdf';
parts.push(...filePart('spec_file', specName, specMime, specData));

// Text fields
parts.push(fieldPart('source_platform', input.source_platform || 'unknown'));
parts.push(fieldPart('platform_reply_info', input.platform_reply_info || '{}'));
parts.push(fieldPart('client_data', input.client_data || '{}'));
parts.push(fieldPart('project_data', input.project_data || '{}'));
parts.push(fieldPart('quotation_config', input.quotation_config || '{}'));
parts.push(fieldPart('boq_media_type', input.boq_media_type || 'xlsx'));
if (input.callback_url) {
  parts.push(fieldPart('callback_url', input.callback_url));
}

parts.push(Buffer.from('--' + boundary + '--' + CRLF));

const body = Buffer.concat(parts);

const resp = await this.helpers.httpRequest({
  method: 'POST',
  url: backendUrl + '/api/integrations/generic/quotation/start',
  headers: {
    Authorization: 'Bearer ' + token,
    'x-tenant-slug': tenantSlug,
    'Content-Type': 'multipart/form-data; boundary=' + boundary,
  },
  body: body,
  json: true,
  timeout: 120000,
});

return [{ json: { project_id: resp.project_id, pipeline_run_id: resp.pipeline_run_id } }];
